 1	import { Controller } from 'react-hook-form';
 2	
 3	import { HelpIconPopover } from '@components/common/HelpIconPopover/HelpIconPopover';
 4	import { Checkbox, FormGroup, Stack, StackItem } from '@patternfly/react-core';
 5	import { useForkliftTranslation } from '@utils/i18n';
 6	
 7	import { useCreatePlanFormContext } from '../../hooks/useCreatePlanFormContext';
 8	
 9	import { otherFormFieldLabels, OtherSettingsFormFieldId } from './constants';
10	
11	const NBDEClevisField = () => {
12	  const { t } = useForkliftTranslation();
13	  const { control } = useCreatePlanFormContext();
14	
15	  return (
16	    <FormGroup
17	      label={otherFormFieldLabels[OtherSettingsFormFieldId.NBDEClevis]}
18	      labelHelp={
19	        <HelpIconPopover>
20	          <Stack hasGutter>
21	            <StackItem>
22	              {t(
23	                'Automatically decrypt LUKS-encrypted disks using Tang servers during migration. The Tang servers must be accessible from the OpenShift cluster.',
24	              )}
25	            </StackItem>
26	            <StackItem>
27	              {t(
28	                'Use this instead of manual passphrases when your VMs are configured with Clevis/Tang for network-bound decryption. This setting applies to all VMs in the plan.',
29	              )}
30	            </StackItem>
31	          </Stack>
32	        </HelpIconPopover>
33	      }
34	    >
35	      <Controller
36	        name={OtherSettingsFormFieldId.NBDEClevis}
37	        control={control}
38	        render={({ field }) => (
39	          <Checkbox
40	            id="nbde-clevis-checkbox"
41	            isChecked={field.value || false}
42	            onChange={(_event, checked) => {
43	              field.onChange(checked);
44	            }}
45	            label={t('Use NBDE/Clevis')}
46	          />
47	        )}
48	      />
49	    </FormGroup>
50	  );
51	};
52	
53	export default NBDEClevisField;

